import{_ as t,o as a,c as i,a0 as n}from"./chunks/framework.CED9SG98.js";const g=JSON.parse('{"title":"The Future Worth Building Is Human","description":"Thinking Machines 关于 AI 与人类协作的深度文章，核心观点：AI 应服务于人类工作而非取代人类，强调分布式隐性知识和去中心化对齐","frontmatter":{"type":"Source","title":"The Future Worth Building Is Human","description":"Thinking Machines 关于 AI 与人类协作的深度文章，核心观点：AI 应服务于人类工作而非取代人类，强调分布式隐性知识和去中心化对齐","source_url":"https://thinkingmachines.ai/blog/the-future-worth-building-is-human/","source_title":"The Future Worth Building Is Human","source_author":"Thinking Machines","source_platform":"网页 (thinkingmachines.ai)","ingest_date":"2026-07-11T00:00:00.000Z","access_date":"2026-07-11T00:00:00.000Z","tags":["AI","人机协作","去中心化","对齐","隐性知识"],"status":"inbox","review_count":0,"last_review":"2026-07-11T00:00:00.000Z","next_review":null},"headers":[],"relativePath":"wiki/sources/2026-07-11-The-Future-Worth-Building-Is-Human.md","filePath":"wiki/sources/2026-07-11-The-Future-Worth-Building-Is-Human.md"}'),o={name:"wiki/sources/2026-07-11-The-Future-Worth-Building-Is-Human.md"};function s(r,e,l,h,d,u){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="the-future-worth-building-is-human" tabindex="-1">The Future Worth Building Is Human <a class="header-anchor" href="#the-future-worth-building-is-human" aria-label="Permalink to &quot;The Future Worth Building Is Human&quot;">​</a></h1><blockquote><p>来源: <a href="https://thinkingmachines.ai/blog/the-future-worth-building-is-human/" target="_blank" rel="noreferrer">https://thinkingmachines.ai/blog/the-future-worth-building-is-human/</a> 日期: Jul 10, 2026 作者: Thinking Machines</p></blockquote><hr><h2 id="初步解读" tabindex="-1">初步解读 <a class="header-anchor" href="#初步解读" aria-label="Permalink to &quot;初步解读&quot;">​</a></h2><p>这篇文章是 <strong>Thinking Machines</strong>（一家 AI 公司）的宣言式文章，核心论点是：<strong>AI 应该扩展人类意志和判断力，而非取代人类</strong>。</p><h3 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h3><ol><li><p><strong>AI 应服务于人类工作</strong></p><ul><li>当前大多数 AI 在少数地方训练后就冻结了，不为使用者所塑造</li><li>AI 需要像人一样多样化和分布式</li></ul></li><li><p><strong>人类知识是分布式、隐性的（tacit knowledge）</strong></p><ul><li>引用 Michael Polanyi（隐性知识）和 Friedrich Hayek（知识在社会中的使用）</li><li>知识是本地化的、不断通过反馈更新的，不能简单提取到数据库</li><li>类比：2014 年丰田将专家工匠带回生产线</li></ul></li><li><p><strong>沟通渠道是技术瓶颈</strong></p><ul><li>当前 LLM 的文本框太窄，无法承载丰富的人类智慧和意图</li><li>需要原生支持实时多模态交互的模型</li></ul></li><li><p><strong>去中心化对齐</strong></p><ul><li>AI 价值观应由每个使用者自己塑造，而不是少数实验室决定</li><li>单一对齐规范会抑制创造力和多样性</li><li>引用 Hannah Arendt《人的条件》</li></ul></li><li><p><strong>衡量标准需要改变</strong></p><ul><li>不应只衡量 AI 自主完成任务的能力（METR 基准）</li><li>应衡量人机协作的整体效果</li></ul></li></ol><h3 id="关键金句" tabindex="-1">关键金句 <a class="header-anchor" href="#关键金句" aria-label="Permalink to &quot;关键金句&quot;">​</a></h3><blockquote><p>&quot;The future is not a choice between human dominance and rapid obsolescence in the face of AI. Different roads lead to many different futures, and we get to choose which one to take.&quot;</p></blockquote><blockquote><p>&quot;We are building technology that lets the born and the made walk the road together.&quot;</p></blockquote><h3 id="关联思考" tabindex="-1">关联思考 <a class="header-anchor" href="#关联思考" aria-label="Permalink to &quot;关联思考&quot;">​</a></h3><ul><li>与 Karpathy 的 llmwiki 理念呼应：AI 是辅助工具，人类保留策展权</li><li>与 Google OKF 的开放知识格式呼应：知识应分布式、可交换</li><li>对 Eason 的启发：在华为推动 AI 应用时，应强调&quot;人机协作&quot;而非&quot;AI 替代&quot;</li></ul><hr><h2 id="原文内容" tabindex="-1">原文内容 <a class="header-anchor" href="#原文内容" aria-label="Permalink to &quot;原文内容&quot;">​</a></h2><p>The mission of Thinking Machines is to build AI that extends human will and judgment.</p><p>Artificial intelligence can do more every day, but deciding what it should do is up to us: individuals, organizations, humanity as a whole. These decisions require knowledge and judgment that people acquire through continuous contact with the work, increasingly done alongside AI. Shaping the goals of advanced intelligence is also a continuous process of feedback, learning, and realignment.</p><p>Most AI in use today is trained in a handful of places and then frozen. It isn&#39;t shaped by the people it serves, and doesn&#39;t learn much from the work they do together. Extending human will and judgment calls for AIs as diverse and distributed as people themselves are. This is the path we have chosen.</p><p>To progress on that path, we are pursuing these technical directions:</p><p>We train strong models, advancing capabilities such as multimodal interaction and customizability. Sharp instruments extend human will, and human judgment needs to shape models that compete on the frontier. We build tools that enable people to make AI their own, customizing models to serve their unique needs. This includes the ability to train model weights. We develop interfaces that broaden the communication channel between human and machine, allowing personal judgment to continuously influence the work of AI. We publish research for the scientific community, because the power to shape AI requires deep understanding of how it&#39;s made.</p><p>We believe the future worth building is human — shaped by human knowledge, guided by human will, and decided by human judgment. What follows is the case for that future, and the work we&#39;re doing to bring it about.</p><h3 id="bringing-intelligence-to-knowledge" tabindex="-1">Bringing intelligence to knowledge <a class="header-anchor" href="#bringing-intelligence-to-knowledge" aria-label="Permalink to &quot;Bringing intelligence to knowledge&quot;">​</a></h3><p>AI exists to serve the work that we do. This work runs on knowledge of how things are done and what is worth doing, knowledge that is generated continuously by people engaged in the work.</p><p>Think of a chef crafting a new recipe or a shopkeeper rearranging the items and prices on display. They are pursuing a complex set of goals and applying know-how that isn&#39;t immediately legible to outsiders. This knowledge is constantly updated through feedback; it&#39;s not a static repository that can be written into a database. It&#39;s local — a different restaurant or shop pursues different outcomes by different means. The collective knowledge of shops and kitchens is scattered across every shopkeeper and chef.</p><p>The dispersion of knowledge is a collective strength; it&#39;s the source of variety, adaptability, and resilience of the overall system. It&#39;s the reason that free markets outperform planned economies. Central planning fails not because of insufficient intelligence, but because of the nature of productive knowledge: tacit, local, fleeting, and held privately by those who acquired it through their work. Attempting to aggregate knowledge for the use of a centralized intelligence faces the same challenge.</p><p>There are domains where intelligence alone is sufficient, and where autonomous AI doesn&#39;t require human participation to race ahead. Two examples are chess, where the strongest engines are trained purely on self-play, and math, where frontier models are solving long-standing problems on their own. These examples share two traits. First, the goal given to AI is static and expressible: to win a chess match, to prove a theorem. Second, these domains don&#39;t contain hidden knowledge. The rules of chess and math are universal; the board is visible to all. Outside the board, intelligence alone is not enough.</p><p>For artificial intelligence to benefit from distributed knowledge, it must itself be distributed. Every organization is powered by the expert knowledge of its people, gained and expressed through their work. We believe in AI that helps the organization cultivate that unique knowledge, not AI that extracts a snapshot of it and replaces it with a standard offering. This cultivation is an ongoing process that requires AI to work with people, not in their stead.</p><p>In 2014, Toyota, long a master of the automated plant, brought its expert craftsmen back onto the line with the explicit goal of growing craftsmanship and knowledge. The man who led this, Mitsuru Kawai, put the reason this way: &quot;To be the master of the machine, you have to have the knowledge and the skills to teach the machine.&quot; The production of knowledge and application of intelligence lift each other; they are not substitutes.</p><p>The work people do may change, and turn toward more of what only people bring, but the best organizations will make the fullest use of both. AI should enable each organization to be excellent in its own way, not to erase the differences between them.</p><p>We aim to bring intelligence to where knowledge is made and used. We build tools that enable everyone to fine-tune models with their unique knowledge, and to keep adapting the models as their knowledge evolves. We publish research and recipes that put this capability within reach of more people. We envision frontier AI as a collective, as diverse as the people it serves because it was shaped by them in each unique location.</p><h3 id="human-participation-is-a-technical-challenge" tabindex="-1">Human participation is a technical challenge <a class="header-anchor" href="#human-participation-is-a-technical-challenge" aria-label="Permalink to &quot;Human participation is a technical challenge&quot;">​</a></h3><p>Keeping people engaged in setting goals and sharing knowledge with AI doesn&#39;t mean resisting automation for its own sake. What a machine does reliably on its own, it should do. But it should also know when to act alone and when to invite oversight and feedback, as people themselves do when working in teams. The best collaborators anticipate: they learn what someone is reaching for and bring it before being asked, earning over time the right to act on their behalf. These are technical challenges, requiring a new approach to how AI is designed and evaluated.</p><p>A major bottleneck for bringing human knowledge and judgment to work with LLMs is the communication channel between human and AI — a small text box and a long wait. This is too narrow to carry the richness of human wisdom and intent, and too slow for ongoing feedback. People collaborate best when they collaborate live. We interrupt and correct, take second looks and make gestures, change our minds aloud. This is why we&#39;re making a long-term bet on interaction models: models that handle live, multimodal interaction natively, in the model itself rather than in scaffolding bolted around it. Built this way, interactivity scales with intelligence; the same training that makes the model smarter makes it a better collaborator. The right interface doesn&#39;t just allow human participation, it invites and rewards it.</p><p>Another challenge is setting the right target for evaluation and optimization. The common measure of AI intelligence today is the time horizon of software tasks models can execute autonomously, tracked on charts like METR&#39;s. We expect progress on this benchmark to continue, but it ultimately measures only what AI is capable of on its own, not what people and machines can accomplish together.</p><p>Measuring the latter is more complex, and can&#39;t be done by a lab on its own. Every organization evaluates for itself whether AI helps it sharpen its judgment, develop new knowledge, and achieve its objectives.</p><p>Building AI that makes its users stronger in the long run also aligns incentives well. An AI lab offering a single model for every customer benefits by absorbing what makes each user distinct and devaluing the cultivation of specialized knowledge. By optimizing AI to be customized and collaborated with, we benefit when our customers leverage their unique advantages. These advantages are maximized not by renting an AI and outsourcing to it, but by organizations owning it and tailoring it to their goals.</p><h3 id="decentralized-alignment" tabindex="-1">Decentralized alignment <a class="header-anchor" href="#decentralized-alignment" aria-label="Permalink to &quot;Decentralized alignment&quot;">​</a></h3><p>Human values, just like human knowledge, reside in the heads of individual people and resist consolidation. But today, the values and voice of AI are decided in a handful of places. A single locus of value alignment, however well run, becomes a locus of power to be captured.</p><p>This creates danger, especially if most valuable work is done by AI on its own with little need for human input. The social contract between corporations, governments, and citizens relies on individuals&#39; productive capabilities on which the government&#39;s sovereignty and corporations&#39; profits ultimately depend. Power that needs nothing from people loses the incentive to care for their needs and values, caring instead for its own preservation.</p><p>Even with the best intentions, a model shaped in one place inevitably encodes the values of its owner, not the individual users it serves. Today each lab trains its next flagship model by using its previous flagship model to generate training data and a reward signal. Whatever character emerges from that loop, everyone gets the same one, and each generation inherits the traits of the last, raised on its parent&#39;s outputs and judged by its parent&#39;s tastes. A single alignment spec suppresses creativity and diversity and stultifies progress. Free speech and free markets let new ideas, goods, and services emerge and compete, rather than averaging out the preferences that exist at a point in time.</p><p>For organizations and individuals to align AI to their own values, these values must be encoded in the model weights. If the user&#39;s values and desires only impact the model through a prompt, the user finds that surface properties change while the deeper habits remain. Allowing core model behavior to change significantly with prompts sacrifices safety, making a malleable centralized model vulnerable to repeated attacks.</p><p>The power to shape a model profoundly is also the power to shape it for ill. John von Neumann remarked on this problem in 1955, writing that the useful and the harmful aspects of technology &quot;lie everywhere so close together that it is never possible to separate the lions from the lambs.&quot; Keeping the lambs safe is an ongoing process, the result of judgment exercised and choices made continuously. We aim to give the people making these choices stronger tools, pursuing research that enables safer models without taking away ownership.</p><p>Humanity has flourished through individual weirdness and creative tension. We envision alignment as a feature not of a single model but of an ecosystem of AIs raised in different places, disagreeing, competing, and learning from each other. We believe in keeping the weirdness alive.</p><h3 id="the-future-worth-building" tabindex="-1">The future worth building <a class="header-anchor" href="#the-future-worth-building" aria-label="Permalink to &quot;The future worth building&quot;">​</a></h3><p>The technology industry has made incredible progress in teaching machines to think; what they should think about must remain with us. What is worth wanting, what is worth making, what&#39;s the right use of the time we have. We are not looking to hand down a single answer to this, but to give every person the ability to make their own answer part of the development of frontier AI.</p><p>The current path of AI development, pushing towards centralization and autonomy, frames human involvement as a trade-off: participation vs. capability, ownership vs. safe alignment. We see these as technical challenges to solve: AI that is more capable because it encourages human participation, organizations that benefit in the long run from tailoring AI to their advantages, alignment that arises from diverse AIs shaped by the people who own them. Solving these challenges is what our mission requires.</p><p>The future is not a choice between human dominance and rapid obsolescence in the face of AI. Different roads lead to many different futures, and we get to choose which one to take. We are building technology that lets the born and the made walk the road together.</p>',46)])])}const p=t(o,[["render",s]]);export{g as __pageData,p as default};
